import React from 'react'
import { Link } from 'gatsby'
import { styled } from 'styled-components'
import NotFound from '../images/void.svg'

const PageContainer = styled.main`
  width: 100%;
  height: 100%;
  display: grid;
  place-items: center;
`

const HeroContainer = styled.div`
  text-align: center;

  & img {
    width: 50%;
  }

  & h1 {
    margin: 1rem 0;
    font-size: 3rem;
  }
`

const StyledLink = styled(Link)`
  display: inline-block;
  color: gray;
  text-decoration: none;
  transition: color 250ms;

  &:hover {
    color: crimson;
  }

  &::after {
    content: '';
    display: block;
    width: 0;
    height: 1px;
    background-color: crimson;
    transition: 500ms;
  }

  &:hover::after {
    width: 100%;
  }
`

const NotFoundPage = () => {
  return (
    <PageContainer>
      <HeroContainer>
        <img src={NotFound} alt='' />
        <h1>404 &mdash; Page not found</h1>
        <p style={{ color: 'lightgray' }}>"And if you gaze long enough into an abyss, the abyss will gaze back into you."</p>
        <p>How about you <StyledLink to='/'>return home</StyledLink> instead?</p>
      </HeroContainer>
    </PageContainer>
  )
}

export default NotFoundPage

export const Head = () => <title>Page not found</title>
